const fs = require('fs');
const path = require('path');
const videoDir = 'C:/videos';

const videoFiles = fs.readdirSync(videoDir)
  .filter(file => /\.(mp4|mov|avi|mkv)$/i.test(file))
  .map(file => ({
    filename: file,
    fullPath: path.join(videoDir, file)
  }));

return videoFiles.map(file => ({ json: file }));

const { execSync } = require('child_process');
const path = require('path');

const videoPath = $json.fullPath;
const videoDir = path.dirname(videoPath);
const videoName = path.basename(videoPath, path.extname(videoPath));

try {
  const command = `whisper "${videoPath}" --output_format txt --output_dir "${videoDir}"`;
  execSync(command, { stdio: 'pipe' });

  return [{
    json: {
      status: 'success',
      videoFile: $json.filename,
      transcriptionFile: `${videoName}.txt`,
      outputPath: path.join(videoDir, `${videoName}.txt`)
    }
  }];
} catch (error) {
  return [{
    json: {
      status: 'error',
      videoFile: $json.filename,
      error: error.message
    }
  }];
}
